const onAppClick = async (click: AppClickInfo) => {
  let rid = click.appid;
  if (rid.startsWith('bdock:')) {
    rid = rid.substring(6);
  } else if (rid.startsWith('bdesk:')) {
    rid = rid.substring(6);
  }

  if (rid == 'launchpad') {
    launchPadclick();
    return;
  }

  if (isShowLauncchPad.value) {
    isShowLauncchPad.value = false;
  }

  let app = appStore.myApps.find((app: any) => app.id == rid);

  if (app) {
    let url = app.url;
    window.open('//' + url);
  } else {
    Notify.create({
      type: 'negative',
      message: rid
    });
  }
};

