
import { ref, defineComponent, onMounted, nextTick, onUnmounted } from 'vue';
import { useQuasar } from 'quasar';
import { useI18n } from 'vue-i18n';

interface WindowRect {
  left: number;
  top: number;
  width: number;
  height: number;
}

export default defineComponent({
  name: 'BasicWindow',
  props: {
    modelValue: {
      type: Object,
      default: () => {
        return {
          id: '',
          width: 400,
          height: 300,
          max_width: 400,
          max_height: 300,
          min_width: 400,
          min_height: 300,
          top: 0,
          left: 0,
          title: '',
          url: '',
          icon: '',
          active: true
        };
      }
    }
  },

  setup(props, context) {
    const { t } = useI18n();
    const value = ref(props.modelValue);
    const h_close = ref(false);
    const h_min = ref(false);
    const h_full = ref(false);
    const h_new = ref(false);
    const isActive = ref(false);
    const isDrag = ref(false);
    const isResize = ref(false);
    const iframeLoad = ref(true);
    const iframeRef = ref();
    const dragRef = ref();
    const isFull = ref(false);
    const clickNew = ref(false);
    const $q = useQuasar();

    const app_icon: string = value.value.icon;

    let dragging = (rect: WindowRect) => {
      if (!value.value.active) {
        context.emit('onTop', value.value);
      }
      isDrag.value = true;
      let callback_obj = {};
      Object.assign(callback_obj, value.value, rect);
      context.emit('update:modelValue', callback_obj);
    };

    let dragStop = () => {
      isDrag.value = false;
    };

    let resizing = (rect: WindowRect) => {
      if (!value.value.active) {
        context.emit('onTop', value.value);
      }
      isResize.value = true;
      let callback_obj = {};
      Object.assign(callback_obj, value.value, rect);
      context.emit('update:modelValue', callback_obj);
    };

    let resizeStop = () => {
      isResize.value = false;
    };

    let activated = () => {
      isActive.value = true;
    };

    let deactivated = () => {
      isActive.value = false;
    };

    let onClose = () => {
      context.emit('close', value.value);
    };

    let onMini = () => {
      context.emit('mini', value.value);
    };

    let onFull = () => {
      isFull.value = !isFull.value;
    };

    let onNew = () => {
      clickNew.value = true;
      setTimeout(() => {
        clickNew.value = false;
      }, 500);

      const href = value.value.redirectUrl || value.value.url;

      window.open(href);
    };

    let onTop = () => {
      if (clickNew.value) {
        return false;
      }
      if (checkDoubleClick()) {
        isFull.value = !isFull.value;
      }
      context.emit('onTop', value.value);
    };

    let lastTapTimeFunc: NodeJS.Timeout;
    let lastTapDiffTime = 0;
    const checkDoubleClick = function () {
      let curT = new Date().getTime();
      let lastT = lastTapDiffTime;
      lastTapDiffTime = curT;
      let diff = curT - lastT;
      if (diff < 300) {
        clearTimeout(lastTapTimeFunc);
        return true;
      } else {
        lastTapTimeFunc = setTimeout(function () {
          return false;
        }, 300);
      }
    };

    const message = (event: any) => {
      if (event.data.message === 'theme_update') {
        if (event.data.info.theme.toString() === '1') {
          $q.dark.set(false);
        } else {
          $q.dark.set(true);
        }
        iframeRef.value.contentWindow.postMessage(
          {
            message: 'theme_apps_update',
            info: event.data.info
          },
          '*'
        );
      }
    };

    onMounted(() => {
      window.addEventListener('message', message);

      nextTick(() => {
        new MutationObserver(function (mutations) {
          mutations.some(function (mutation) {
            if (
              mutation.type === 'attributes' &&
              mutation.attributeName === 'src'
            ) {
              return true;
            }

            return false;
          });
        }).observe(document.body, {
          attributes: true,
          attributeFilter: ['src'],
          attributeOldValue: true,
          characterData: false,
          characterDataOldValue: false,
          childList: false,
          subtree: true
        });

        if (iframeRef.value.attachEvent) {
          // IE
          iframeRef.value.attachEvent('onload', () => {
            iframeLoad.value = false;
          });
        } else {
          // not IE
          iframeRef.value.onload = function () {
            iframeLoad.value = false;
          };
        }
      });
    });

    onUnmounted(() => {
      window.removeEventListener('message', message);
    });

    return {
      $q,
      value,
      isActive,
      isDrag,
      isResize,
      h_close,
      h_min,
      h_full,
      h_new,
      app_icon,
      iframeLoad,
      iframeRef,
      dragRef,
      isFull,
      dragging,
      dragStop,
      resizing,
      resizeStop,
      activated,
      deactivated,
      onClose,
      onMini,
      onFull,
      onTop,
      onNew,
      t
    };
  }
});
